<template>
	<view>
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<u-popup v-model="detailshow" mode="center" :z-index="9" :custom-style="{marginBottom:'100rpx'}"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			@close="close">
			<view class="popup-content">
				<u-form :model="form" ref="uForm" :rules="rules" label-width="130">
					<u-form-item label="手机号码" prop="mobile"><u-input v-model.trim="form.mobile" clearable
							placeholder="请输入手机号码" :disabled="true" /></u-form-item>
					<u-form-item label="验证码" prop="captcha"><u-input v-model.trim="form.captcha" :clearable="false"
							maxlength="6" placeholder="请输入验证码" />
						<u-button @click="sendCode" type="success" size="mini"
							style="width: 160rpx;">{{tips}}</u-button>
						<u-verification-code :seconds="60" ref="uCode" @start="codeStart" @end="codeEnd"
							@change="codeChange" start-text="获取验证码"
							change-text="X秒"></u-verification-code></u-form-item>
				</u-form>
				<view class="btns">
					<u-button @click="save" class="submit-btn">确定</u-button>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	import SlideCodeMixin from './slideCode.mixin'
	export default {
		mixins: [SlideCodeMixin],
		components: {
			
		},
		props: {

		},
		data() {
			return {
				detailshow: false,
				form: {
					mobile: '',
					captcha: '',
				},
				rules: {
					mobile: [{
						required: true,
						trigger: 'blur',
						message: '请输入登录的手机号码！'
					}, {
						// 自定义验证函数，见上说明
						validator: (rule, value, callback) => {
							// 上面有说，返回true表示校验通过，返回false表示不通过
							// this.$u.test.mobile()就是返回true或者false的
							return this.$u.test.mobile(value);
						},
						message: '手机号码不正确',
						// 触发器可以同时用blur和change
						trigger: ['change', 'blur'],
					}],
					captcha: [{
						required: true,
						trigger: 'blur',
						message: '请输入短信验证码！'
					}]
				},			
			}
		},
		watch: {

		},
		mounted() {
			
		},
		methods: {			
			show({
				mobile
			}) {
				this.form.mobile = mobile
				this.detailshow = true
			},
			close() {
				this.is_sendCode = false
				this.detailshow = false
			},
			sendCode() {
				if (this.is_sendCode)
					return
				this.$refs['uForm'].setRules({
					mobile: this.rules.mobile
				})
				this.$refs['uForm'].validate((e) => {
					if (e) {
						this.slideCode[0].show = true
					}
				})
			},
			async getCode() {
				if (this.$refs.uCode.canGetCode) {
					let data = {
						send_type: 15,
						mobile: this.form.mobile,
						session: this.session_id[0],
					}
					await this.$u.api.sendCode(data)
					this.$util.msg('验证码已发送')
					this.$refs.uCode.start()
				}
			},
			save() {
				this.$refs['uForm'].setRules(this.rules)
				this.$refs['uForm'].validate(async (e) => {
					if (e) {
						await this.$u.api.unbind_mobile({
							mobile: this.form.mobile,
							captcha: this.form.captcha
						})
						this.userinfo.mobile = ''
						this.$u.vuex('userinfo',this.userinfo)
						this.$u.toast('解绑成功')
						this.close()
						this.$emit('fetch-data')
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 50rpx 40rpx;

		.btns {
			width: 100%;

			.submit-btn {
				display: inline-block;
				width: 200rpx;
				height: 60rpx;
				line-height: 60rpx;
				margin-left: 130rpx;
				margin-top: 30rpx;
			}
		}

	}
</style>