<template>
	<view>
		<u-popup v-model="detailshow" mode="center" :z-index="9" :custom-style="{marginBottom:'100rpx'}"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			@close="close">
			<view class="popup-content">
				<u-form :model="form" ref="uForm" :rules="rules" label-width="130">
					<u-form-item label="旧密码" prop="password" v-if="hasPassword">
						<u-input v-model.trim="form.password" type="password" clearable placeholder="请输入旧密码" />
					</u-form-item>
					<u-form-item label="新密码" prop="new_password">
						<u-input v-model.trim="form.new_password" type="password" clearable placeholder="请输入新的密码" />
					</u-form-item>
					<u-form-item label="重复密码" prop="two_password">
						<u-input v-model.trim="form.two_password" type="password" clearable placeholder="请输入重复密码" />
					</u-form-item>
				</u-form>
				<view class="btns">
					<u-button @click="save" class="submit-btn">确定</u-button>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {

		},
		data() {
			const validatePass = (rule, value, callback) => {
				if (value === '' || value.length < 6) {
					callback(new Error('请输入不少于6位的密码'))
				} else {
					callback()
				}
			}
			const validateCheckPass = (rule, value, callback) => {
				if (value === '') {
					callback(new Error('请再次输入密码'))
				} else if (value !== this.form.new_password) {
					callback(new Error('两次输入密码不一致!'))
				} else {
					callback()
				}
			}
			return {
				detailshow: false,
				hasPassword: 0,
				form: {
					password: '',
					new_password: '',
					two_password: '',
				},
				rules: {
					password: [{
						required: true,
						trigger: 'blur',
						message: '请输入旧密码！'
					}],
					new_password: [{
						required: true,
						trigger: 'blur',
						validator: validatePass,
					}],
					two_password: [{
						required: true,
						trigger: 'blur',
						validator: validateCheckPass,
					}],
				},
			}
		},
		watch: {

		},
		mounted() {

		},
		methods: {
			show({
				has_password
			}) {
				this.hasPassword = has_password
				this.detailshow = true
			},
			close() {
				this.$refs['uForm'].resetFields()
				this.form = this.$options.data().form
				this.detailshow = false
			},
			save() {
				this.$refs['uForm'].setRules(this.rules)
				this.$refs['uForm'].validate(async (e) => {
					if (e) {
						await this.$u.api.setPassword(this.form)						
						this.$u.toast('保存成功')
						this.close()
						this.$emit('fetch-data')
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 50rpx 40rpx;

		.btns {
			width: 100%;

			.submit-btn {
				display: inline-block;
				width: 200rpx;
				height: 60rpx;
				line-height: 60rpx;
				margin-left: 130rpx;
				margin-top: 30rpx;
			}
		}

	}
</style>