<template>
	<view>
		<u-popup v-model="detailshow" mode="center" :z-index="9" :custom-style="{marginBottom:'100rpx'}"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="popup-content">
				<u-form :model="form" ref="uForm" :rules="rules" label-width="130">
					<template v-if="hasTradePassword">
						<u-form-item label="旧密码" prop="trade_password"><u-input v-model.trim="form.trade_password"
								type="password" clearable placeholder="请输入旧密码" :maxlength="6"  /></u-form-item>
						<u-form-item label="新密码" prop="new_trade_password"><u-input :maxlength="6" 
								v-model.trim="form.new_trade_password" type="password" clearable
								placeholder="请输入新密码" /></u-form-item>
						<u-form-item label="重复密码" prop="two_trade_password"><u-input
								v-model.trim="form.two_trade_password" type="password" :maxlength="6"  clearable
								placeholder="请输入重复密码" /></u-form-item>
						<u-form-item label="绑定功能" prop="trade_password_list">
							<u-checkbox-group @change="checkboxChange">
								<u-checkbox v-model="item.checked" v-for="(item, index) in sceneList" :key="index"
									:name="item.value">{{item.label}}</u-checkbox>
							</u-checkbox-group>
						</u-form-item>
					</template>
					<template v-else>
						<u-form-item label="密码" prop="new_trade_password"><u-input
								v-model.trim="form.new_trade_password" type="password" clearable
								placeholder="请输入密码" /></u-form-item>
						<u-form-item label="绑定功能" prop="trade_password_list">
							<u-checkbox-group @change="checkboxChange">
								<u-checkbox v-model="item.checked" v-for="(item, index) in sceneList" :key="index"
									:name="item.value">{{item.label}}</u-checkbox>
							</u-checkbox-group>
						</u-form-item>
					</template>
				</u-form>
				<view class="btns">
					<u-button @click="save" class="submit-btn">确定</u-button>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {

		},
		data() {
			const validateOldPass = (rule, value, callback) => {
				if (value === '') {
					callback(new Error('请输入交易密码'))
				} else {
					callback()
				}
			}
			return {
				hasTradePassword: 0,
				sceneList: [],
				form: {
					trade_password: '',
					new_trade_password: '',
					two_trade_password: '',
					trade_password_list: [],
				},
				rules: {
					trade_password: [{
						required: true,
						validator: validateOldPass,
						trigger: 'blur'
					}],
					trade_password_list: [{
						type: 'array',
						required: true,
						message: '请至少选择一个绑定功能',
						trigger: 'change'
					}]
				},
				detailshow: false,
			}
		},
		watch: {

		},
		mounted() {

		},
		methods: {
			show({
				has_trade_password,
				trade_password_list,
			}) {
				this.detailshow = true
				this.hasTradePassword = has_trade_password ? true : false
				this.form.trade_password_list = trade_password_list
			},
			close() {
				this.sceneList = []
				this.form = this.$options.data().form
				this.detailshow = false
			},
			open() {
				this.$u.api.tradePasswordList().then(res => {
					this.sceneList = res.map(item => {
						let find = this.form.trade_password_list.includes(item.value)
						item.checked = find?true:false
						return item
					})
				})
			},
			checkboxChange() {
				this.form.trade_password_list = this.sceneList.filter(item => item.checked == true).map(item => item.value)
			},
			save() {
				this.$refs['uForm'].setRules(this.rules)
				this.$refs['uForm'].validate(async (e) => {
					if (e) {
						await this.$u.api.setTradePassword(this.form)
						this.$u.toast('保存成功')
						this.close()
						this.$emit('fetch-data')
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 50rpx 40rpx;

		.btns {
			width: 100%;

			.submit-btn {
				display: inline-block;
				width: 200rpx;
				height: 60rpx;
				line-height: 60rpx;
				margin-left: 130rpx;
				margin-top: 30rpx;
			}
		}

	}
</style>