<template>
	<view>
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<template v-if="hasSelectPopup">
			<select-popup :show.sync="selectShow" />
		</template>
		<template v-else>
			<view-popup :type="viewType" :show.sync="viewShow" />
		</template>
	</view>
</template>

<script>
	// 统一手机号码和邮箱验证
	import SelectPopup from './select-popup'
	import ViewPopup from './view-popup'
	import slideCode from '@/components/slideCode.vue'

	// 支持可以验证的方式
	const allowVerifyList = [{
			label: '短信验证',
			value: 'mobile',
		},
		{
			label: '邮箱验证',
			value: 'email',
		}
	]
	export default {
		name: 'verify-popup',
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			// 验证类型，
			type: {
				type: Array,
				required: true,
				validator(value) {
					const arr = allowVerifyList.map(item => item.value)
					let flag = true
					value.forEach(item => {
						if (!arr.includes(item))
							flag = false
					})
					return flag
				},
			},
			// 验证码类型
			codeType: {
				type: Object,
			},
		},
		components: {
			slideCode,
			'select-popup': SelectPopup,
			'view-popup': ViewPopup,
		},
		data() {
			return {
				selectShow: false,
				viewShow: false,
				viewType: '',
				slideCode: [{
					show: false
				}],
				session_id: [],
				eventName: ''
			}
		},
		computed: {
			//是否存在选择弹框
			hasSelectPopup() {
				return this.type.length > 1 ? true : false
			},
		},
		watch: {
			show(nv) {
				if (this.hasSelectPopup) {
					this.selectShow = nv
				} else {
					this.viewType = this.type[0]
					this.viewShow = nv
				}
			}
		},
		provide() {
			return {
				verifyList: () => {
					return this.$_.filter(allowVerifyList, (item) => {
						return this.$_.includes(this.type, item.value)
					})
				},
				cancel: (e) => {
					this.$emit('cancel', e)
				},
				ok: (e) => {
					this.$emit('ok', e)
				},
				getSession: () => this.session_id[0],
				showSlideCode: (e) => {
					this.eventName = e
					this.slideCode[0].show = true
				},
				getCodeType: (e) => {
					if (Reflect.has(this.codeType, e)) {
						return this.codeType[e]
					} else {
						return ''
					}
				}
			}
		},
		methods: {
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值
				uni.$emit(this.eventName)
			},
		},
		created() {
			this.$slideCode_init(0); //初始化图形滑块
		}
	}
</script>

<style lang="scss" scoped scoped>
</style>