<template>
	<u-popup v-model="popupShow" mode="center" :z-index="9" :custom-style="{marginBottom:'100rpx'}"
		:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :mask-close-able="false" :border-radius="20"
		:closeable="false">
		<view class="popup-title">
			{{title}}
			<view class="close-btn" @click="close">
				<u-icon name="close" color="#82848a"></u-icon>
			</view>
		</view>
		<view class="popup-content">
			<mobile-verify v-if="type=='mobile'" />
			<email-verify v-else-if="type == 'email'" />
		</view>
	</u-popup>
</template>

<script>
	import MobileVerify from './mobile-verify'
	import EmailVerify from './email-verify'

	export default {
		props: {
			show: {
				type: Boolean,
				default: false
			},
			type: {
				type: String,
				// required: true
			}
		},
		components: {
			'mobile-verify': MobileVerify,
			'email-verify': EmailVerify,
		},
		data() {
			return {
				popupShow: false
			}
		},
		computed: {
			title() {
				const find = this.verifyList().find(item => item.value == this.type)
				return find ? find.label : '未知验证方式'
			}
		},
		inject: ['verifyList', 'cancel'],
		watch: {
			show(nv) {
				this.popupShow = nv
			},
		},
		methods: {
			close() {
				this.cancel()
				this.$emit('update:show', false)
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
		position: relative;

		.close-btn {
			position: absolute;
			line-height: 1;
			z-index: 2;
			right: 30rpx;
			top: 50%;
			transform: translateY(-50%);
			padding: 10rpx;
		}
	}

	.popup-content {
		padding: 40rpx 40rpx 40rpx 50rpx;
	}
</style>