<template>
	<view>
		<u-popup v-model="selectShow" mode="bottom" :z-index="9" :custom-style="{}"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :mask-close-able="false" :border-radius="20"
			:closeable="false">
			<view class="popup-title">
				选择验证方式
				<view class="close-btn" @click="close">
					<u-icon name="close" color="#82848a"></u-icon>
				</view>
			</view>
			<view class="popup-content">
				<u-cell-group>
					<u-cell-item @click="selectItemClick(item)" :title="item.label" v-for="(item,index) in selectList"
						:key="index" />
				</u-cell-group>
			</view>
		</u-popup>
		<view-popup :type="currVerify.value" :show.sync="viewShow" />
	</view>
</template>

<script>
	import ViewPopup from './view-popup'
	export default {
		props: {
			show: {
				type: Boolean,
				default: false
			},
		},
		components: {
			'view-popup': ViewPopup,
		},
		data() {
			return {
				selectShow: false,
				currVerify: {},

				viewShow: false,
			}
		},
		computed: {
			selectList() {
				return this.verifyList()
			},
		},
		inject: ['verifyList', 'cancel'],
		watch: {
			show(nv) {
				if (nv === true)
					this.selectShow = nv
				else {
					this.selectShow = nv
					this.viewShow = nv
				}
			}
		},
		methods: {
			selectItemClick(e) {
				this.currVerify = e
				this.selectShow = false
				this.viewShow = true
			},
			close() {
				this.cancel()
				this.$emit('update:show', false)
			}
		},
	}
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
		position: relative;

		.close-btn {
			position: absolute;
			line-height: 1;
			z-index: 2;
			right: 30rpx;
			top: 50%;
			transform: translateY(-50%);
			padding: 10rpx;
		}
	}

	.popup-content {
		min-height: 300rpx;
		max-height: 600rpx;
	}
</style>