<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="false"
			:duration="150" @close="close" @open="open">
			<view class="menu-box">
				<view class="menu-list">
					<view class="menu-item" v-for="(item,index) in list" :key="index" @click="menuClick(item,index)">
						{{item}}
					</view>
					<view class="menu-item cancel-item" @click="handelCancel">取消</view>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			},
			value: {
				type: Boolean,
				default: false
			},
			list: {
				type: Array,
				required: true,
				default: () => []
			}
		},
		data() {
			return {

			}
		},
		computed: {
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				}
			},
		},
		methods: {
			open() {

			},
			close() {},
			menuClick(item, index) {
				this.$emit('change', {
					item,
					index
				})
			},
			handelCancel() {
				this.popupShow = false
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.menu-box {
		background-color: #ddd;

		.menu-list {
			display: flex;
			flex-direction: column;
			font-size: 28rpx;
			font-weight: 500;

			.menu-item {
				width: 100%;
				padding: 30rpx;
				text-align: center;
				background-color: #fff;

				&+.menu-item {
					border-top: 1px solid #e5e5e5;
				}

				&:active {
					background-color: #ddd;
				}
			}
		}

		.cancel-item {
			margin-top: 20rpx;
		}
	}
</style>