<template>
	<view>
		<u-form :model="form" ref="uForm" :rules="rules" label-width="130">
			<u-form-item label="手机号码" prop="mobile"><u-input v-model.trim="form.mobile" clearable
					placeholder="请输入手机号码" /></u-form-item>
			<u-form-item label="验证码" prop="code"><u-input v-model.trim="form.code" :clearable="false" maxlength="6"
					placeholder="请输入验证码" />
				<u-button @click="sendCode" type="success" size="mini" style="width: 160rpx;">{{tips}}</u-button>
				<u-verification-code :seconds="60" ref="uCode" @start="codeStart" @end="codeEnd" @change="codeChange"
					start-text="获取验证码" change-text="X秒"></u-verification-code></u-form-item>
		</u-form>
		<view class="btns">
			<u-button @click="save" class="submit-btn">确定</u-button>
		</view>
	</view>
</template>

<script>
	import SlideCodeMixin from './slideCode.mixin'
	export default {
		components: {

		},
		mixins: [SlideCodeMixin],
		props: {

		},
		data() {
			return {
				form: {
					mobile: '',
					code: '',
				},
				rules: {
					mobile: [{
						required: true,
						trigger: 'blur',
						message: '请输入登录的手机号码！'
					}, {
						validator: (rule, value, callback) => {
							return this.$u.test.mobile(value);
						},
						message: '手机号码不正确',
						trigger: ['change', 'blur'],
					}],
					code: [{
						required: true,
						trigger: 'blur',
						message: '请输入短信验证码！'
					}]
				},

			}
		},
		inject: ['showSlideCode', 'getSession', 'ok', 'getCodeType'],
		watch: {

		},
		mounted() {
			const {
				mobile
			} = this.userinfo
			this.form.mobile = mobile
		},
		methods: {
			sendCode() {
				if (!this.$refs.uCode.canGetCode)
					return
				this.$refs['uForm'].setRules({
					mobile: this.rules.mobile
				})
				this.$refs['uForm'].validate((e) => {
					if (e) {
						uni.$once('verifyPopupMobileSuccess', this.verifySuccess)
						this.showSlideCode('verifyPopupMobileSuccess')
					}
				})
			},
			async verifySuccess(params) {
				this.getCode()
			},
			async getCode() {
				if (this.$refs.uCode.canGetCode) {
					let data = {
						send_type: 17,
						mobile: this.form.mobile,
						session: this.getSession(),
					}
					data.send_type = this.getCodeType('mobile')
					await this.$u.api.sendCode(data)
					this.$util.msg('验证码已发送')
					this.$refs.uCode.start()
				}
			},
			save() {
				this.$refs.uForm.setRules(this.rules)
				this.$refs['uForm'].validate(async (e) => {
					if (e) {
						this.ok({
							type: 'mobile',
							...this.form
						})
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.btns {
		width: 100%;
		margin-left: 130rpx;
		margin-top: 30rpx;

		.submit-btn {
			display: inline-block;
			width: 200rpx;
			height: 60rpx;
			line-height: 60rpx;
		}
	}
</style>