<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}" :border-radius="20"
		width="500rpx" :closeable="true" @close="close">
		<view class="popup-content">
			<view class="title">
				打开微信 扫码
			</view>
			<view class="qrcode" v-if="qrcodeurl">
				<uqrcode ref="uqrcode" canvas-id="qrcode" sizeUnit="rpx" size="300" :value="qrcodeurl"></uqrcode>
			</view>
		</view>
	</u-popup>
</template>

<script>
	export default {
		props: {},
		data() {
			return {
				popupShow: false,
				qrcodeurl: ','
			}
		},
		watch: {
			qrcodeshow: {
				handler(nv) {
					this.show = this.qrcodeshow
				},
			}
		},
		mounted() {

		},
		methods: {
			show({
				url
			}) {
				this.qrcodeurl = url
				this.popupShow = true
			},
			close() {

			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		.qrcode {
			width: 300rpx;
			height: 300rpx;
		}
	}
</style>