<template>
	<view class="set-page">
		<view class="page-wrap">
			<view class="user">
				<view class="user-wrap">
					<view class="img">
						<u-image shape="circle" width="140rpx" height="140rpx" :src="user.avatar"></u-image>
					</view>
					<view class="right">
						<view class="item">
							<view class="title">会员UID</view>
							<view class="info">{{user.uid}}</view>
						</view>
						<view class="item">
							<view class="title">注册日期</view>
							<view class="info">{{user.create_time}}</view>
						</view>
						<view class="item">
							<view class="title">安全级别</view>
							<view class="info"><u-line-progress active-color="#2979ff"
									:percent="safeValue"></u-line-progress><text class="tip"
									v-if="safeValue != 100">建议您启动全部安全设置，以保障账户及资金安全。</text></view>
						</view>
					</view>
				</view>
			</view>
			<view class="set-box">
				<view class="set-wrap">
					<view class="item">
						<text class="iconfont icon-shouji"></text>
						<view class="name">实名认证</view>
						<view class="operate">
							<view class="btn" v-if="user.has_certify">已认证</view>
							<view class="btn" v-else @click="handelBindCertification">去认证</view>
						</view>
					</view>
					<view class="item">
						<text class="iconfont icon-shouji"></text>
						<view class="name">手机绑定</view>
						<view class="operate">
							<view class="btn" v-if="user.mobile" @click="handelUnBindMobile">解绑</view>
							<view class="btn" v-else @click="handelBindMobile">绑定</view>
						</view>
					</view>
					<view class="item">
						<text class="iconfont icon-youxiang"></text>
						<view class="name">邮箱绑定</view>
						<view class="operate">
							<view class="btn" v-if="user.email" @click="handelUnBindEmail">解绑</view>
							<view class="btn" v-else @click="handelBindEmail">绑定</view>
						</view>
					</view>
				<view class="item" v-if="!user.close_bind_wx">
						<text class="iconfont icon-weixin1"></text>
						<view class="name">微信绑定</view>
						<view class="operate">
							<view class="btn" v-if="user.bind_wechat" @click="handelUnbindWx">解绑</view>
							<view class="btn" v-else @click="handelBindWx">绑定</view>
						</view>
					</view>
					<view class="item" v-if="!user.close_bind_qq">
						<text class="iconfont icon-QQ1"></text>
						<view class="name">QQ绑定</view>
						<view class="operate">
							<view class="btn" v-if="user.bind_qq" @click="handelUnBindQQ">解绑</view>
							<view class="btn" v-else @click="handelBindQQ">绑定</view>
						</view>
					</view>
					<view class="item">
						<text class="iconfont icon-mima1"></text>
						<view class="name">登录密码</view>
						<view class="operate">
							<u-switch v-model="user.password_open" :active-value="1" :inactive-value="0" :size="40"
								@change="handelOpenPassword"></u-switch>
							<view class="btn" v-if="user.has_password" @click="editPassword">修改</view>
							<view class="btn" v-else @click="editPassword">设置</view>
						</view>
					</view>
					<view class="item" v-if="user.open_pay_password">
						<text class="iconfont icon-mima"></text>
						<view class="name">交易密码</view>
						<view class="operate">
							<u-switch v-model="user.trade_password_open" :active-value="1" :inactive-value="0"
								:size="40" @change="handelOpenTradePassword"></u-switch>
							<view class="btn" v-if="user.has_trade_password" @click="editTradePassword">修改</view>
							<view class="btn" v-else @click="editTradePassword">设置</view>
						</view>
					</view>
					<view class="item">
						<text class="iconfont icon-APIwangguan"></text>
						<view class="name">接口密钥</view>
						<view class="operate">
							<view class="btn" @click="$util.on('/pages/ucenter_sub/set_api')">设置</view>
						</view>
					</view>
				</view>
			</view>
			<view class="logout">
				<u-button type="error" @click="showConfirm=true">退 出</u-button>
			</view>
		</view>
		<loginout-confirm v-model="showConfirm" :list="['退出登录']" @change="handelConfirm" />
		<bind-mobile ref="bind_mobile" @fetch-data="fetchData" />
		<unbind-mobile ref="unbind_mobile" @fetch-data="fetchData" />
		<bind-email ref="bind_email" @fetch-data="fetchData" />
		<unbind-email ref="unbind_email" @fetch-data="fetchData" />
		<login-password ref="login_password" @fetch-data="fetchData" />
		<trade-password ref="trade_password" @fetch-data="fetchData" />
		<password-input :popupShow.sync="showPassInput" @ok="handelPasswordInputOk" @close="handelPasswordInputClose" />
		<wx-scan-qrcode ref='wx_scan_qrcode' />
		<unbind-weixin ref="unbind_weixin" @fetch-data="fetchData" />
		<unbind-qq ref="unbind_qq" @fetch-data="fetchData" />
		<!-- <bind-certification ref="bind_certification" @fetch-data="fetchData" /> -->
		<verify-popup :show="verifyShow" :type="verifyType" :code-type="verifyCodeType" @cancel="handelVerifyCancel"
			@ok="handelVerifyOk" />
	</view>
</template>

<script>
	import Confirm from '@/components/confirm'
	import BindMobile from './components/BindMobile'
	import UnBindMobile from './components/UnBindMobile'
	import BindEmail from './components/BindEmail'
	import UnBindEmail from './components/UnBindEmail'
	import LoginPassword from './components/LoginPassword'
	import TradePassword from './components/TradePassword'
	import PasswordInput from '@/components/password-input/index'
	import WxScanQRCode from './components/WxScanQRCode'
	import UnBindWeixin from './components/UnBindWeixin'
	import UnBindQQ from './components/UnBindQQ'
	// import BindCertification from './components/BindCertification'
	import VerifyPopup from '@/components/verify-popup'
	import {
		mapMutations,
		mapActions
	} from 'vuex'
	export default {
		components: {
			'loginout-confirm': Confirm,
			'bind-mobile': BindMobile,
			'unbind-mobile': UnBindMobile,
			'bind-email': BindEmail,
			'unbind-email': UnBindEmail,
			'login-password': LoginPassword,
			'trade-password': TradePassword,
			'password-input': PasswordInput,
			'wx-scan-qrcode': WxScanQRCode,
			'unbind-weixin': UnBindWeixin,
			'unbind-qq': UnBindQQ,
			// 'bind-certification': BindCertification,
			'verify-popup': VerifyPopup,
		},
		data() {
			return {
				showConfirm: false,
				user: {},
				showPassInput: false,
				verifyShow: false,
			}
		},
		onLoad() {
			this.fetchData()
		},
		onHide() {

		},
		computed: {
			safeValue() {
				return this.user.safe_num && this.user.safe_max ? Math.floor(this.user.safe_num / this.user.safe_max *
					100) : 0
			},
			verifyType() {
				const re = []
				const {
					email,
					mobile
				} = this.userinfo
				if (email)
					re.push('email')
				if (mobile)
					re.push('mobile')

				return re
			},
			verifyCodeType() {
				const re = {}
				const {
					email,
					mobile
				} = this.userinfo
				if (email)
					re.email = 'closepwd'
				if (mobile)
					re.mobile = 17
				return re
			},
		},
		methods: {
			...mapMutations(['updateUserInfo']),
			...mapActions(['logout']),
			async fetchData() {
				const data = await this.$u.api.ucenterset()
				this.user = data
				// this.$u.vuex('userinfo.has_trade_password', this.user.has_trade_password);

				const res = await this.$u.api.userinfo()
				let userinfo = res.userinfo
				userinfo.isLogin = true
				this.updateUserInfo(userinfo)
			},
			handelBindMobile() {
				this.$refs['bind_mobile'].show()
			},
			handelUnBindMobile() {
				this.$refs['unbind_mobile'].show({
					mobile: this.user.mobile
				})
			},
			handelBindEmail() {
				this.$refs['bind_email'].show()
			},
			handelUnBindEmail() {
				this.$refs['unbind_email'].show({
					email: this.user.email
				})
			},
			editPassword() {
				this.$refs['login_password'].show({
					has_password: this.user.has_password,
				})
			},
			// 开启关闭登录密码
			async handelOpenPassword(e) {
				//关才要验证
				if (e) {
					await this.$u.api.setPasswordOpen({
						status: e
					})
					this.$u.toast('保存成功')
				} else {
					if (!Object.keys(this.verifyCodeType).length) {
						this.$util.msg('请先绑定手机或邮箱')
						return
					}
					this.verifyShow = true
				}
			},
			// 验证取消
			handelVerifyCancel() {
				this.verifyShow = false
				this.user.password_open = 1
			},
			// 验证回调
			async handelVerifyOk(e) {
				try {
					await this.$u.api.setPasswordOpen({
						status: 0,
						verify: e
					})
					this.verifyShow = false
					this.user.password_open = 0
					this.$u.toast('保存成功')
				} catch (err) {
					this.user.password_open = 1
				}
			},
			editTradePassword() {
				this.$refs['trade_password'].show({
					has_trade_password: this.user.has_trade_password,
					trade_password_list: this.user.trade_password_list,
				})
			},
			handelOpenTradePassword(e) {
				//关才要验证交易密码
				if (e) {
					this.$u.api.setTradePasswordOpen({
						status: 1
					}).then(() => {
						this.$u.toast('保存成功')
					})
				} else {
					this.showPassInput = true
				}
			},
			handelPasswordInputOk(e) {
				this.$u.api.setTradePasswordOpen({
					trade_password: e,
					status: 0
				}).then(() => {
					this.$u.vuex('userinfo.has_trade_password', true)
					this.$u.toast('关闭成功')
				}).catch(() => {
					this.user.trade_password_open = 1
				})
			},
			handelPasswordInputClose() {
				this.user.trade_password_open = 1
			},
			async handelBindWx() {
				const {
					wx_login_type,
					url
				} = await this.$u.api.loginEventUrl({
					event: 'bind',
					type: 'weixin',
				})
				// 扫码
				if (wx_login_type == 2) {
					// this.$u.toast('暂未实现')
					this.$refs['wx_scan_qrcode'].show({
						url
					})
				}
				// 跳转地址
				else if (wx_login_type == 1) {
					this.$util.msg('三方登录跳转中', 10000);
					// window.open(url)
					setTimeout(() => window.open(url))

				}
			},
			handelUnbindWx() {
				this.$refs['unbind_weixin'].show({
					mobile: this.user.mobile
				})
			},
			async handelBindQQ() {
				const {
					url
				} = await this.$u.api.loginEventUrl({
					event: 'bind',
					type: 'qq',
				})
				this.$util.msg('三方登录跳转中', 10000);
				// window.open(url)
				setTimeout(() => window.open(url))
			},
			handelUnBindQQ() {
				this.$refs['unbind_qq'].show({
					mobile: this.user.mobile
				})
			},
			// 实名认证
			handelBindCertification() {

				if (!this.user.mobile) {
					this.$util.msg('请先绑定手机号码')
				} else {
					this.$util.on('/pages/ucenter_sub/certify/index')
				}

				// this.$refs['bind_certification'].show()
			},
			async doLogout() {
				await this.$u.api.logout()
				await this.logout()

				uni.redirectTo({
					url: '/pages/user/login'
				})
			},
			handelConfirm(e) {
				const {
					index
				} = e
				if (index === 0) {
					this.doLogout()
				}
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.set-page {
		background-color: #fff;

		.page-wrap {
			padding: 20rpx;
		}

		.user {
			background-color: #F7F9FA;
			border: 1px solid #ddd;
			border-radius: 10rpx;

			.user-wrap {
				padding: 40rpx;
				display: flex;
				align-items: flex-start;
				gap: 20rpx;

				.img {
					width: 140rpx;
				}

				.right {
					display: flex;
					flex-direction: column;
					gap: 20rpx;
					flex: 1;

					.item {
						display: flex;
						gap: 0rpx;
						width: 100%;

						.title {
							color: #A0A2A3;
							width: 130rpx;
							white-space: nowrap;
						}

						.info {
							flex: 1;

							.tip {
								color: #ff6600;
							}
						}
					}
				}
			}
		}

		.set-box {
			.set-wrap {
				.item {
					display: flex;
					align-items: center;
					padding: 20rpx;

					&>.iconfont {
						font-size: 50rpx;
						width: 80rpx;
						color: rgb(153, 153, 153);
					}

					.name {
						flex: 1;
					}

					.operate {
						display: flex;
						align-items: center;
						gap: 30rpx;

						.btn {
							white-space: nowrap;
							color: #2979FF;
						}
					}
				}

				.item+.item {
					border-top: 1px dashed #ddd;
				}
			}
		}

		.logout {
			padding: 20rpx;
		}
	}
</style>