<template>
	<view>
		<u-form :model="form" ref="uForm" :rules="rules" label-width="130">
			<u-form-item label="邮箱" prop="email"><u-input v-model.trim="form.email" clearable
					placeholder="请输入邮箱" /></u-form-item>
			<u-form-item label="验证码" prop="code"><u-input v-model.trim="form.code" :clearable="false" maxlength="6"
					placeholder="请输入验证码" />
				<u-button @click="sendCode" type="success" size="mini" style="width: 160rpx;">{{tips}}</u-button>
				<u-verification-code :seconds="60" ref="uCode" @start="codeStart" @end="codeEnd" @change="codeChange"
					start-text="获取验证码" change-text="X秒"></u-verification-code></u-form-item>
		</u-form>
		<view class="btns">
			<u-button @click="save" class="submit-btn">确定</u-button>
		</view>
	</view>
</template>

<script>
	import SlideCodeMixin from './slideCode.mixin'
	export default {
		mixins: [SlideCodeMixin],
		components: {

		},
		props: {

		},
		data() {
			return {
				form: {
					email: '',
					code: '',
				},
				rules: {
					email: [{
						required: true,
						type: 'email',
						trigger: 'blur',
						message: '请输入邮箱地址！'
					}],
					code: [{
						required: true,
						trigger: 'blur',
						message: '请输入验证码！'
					}]
				},
			}
		},
		inject: ['showSlideCode', 'getSession', 'ok', 'getCodeType'],
		watch: {

		},
		mounted() {
			const {
				email
			} = this.userinfo
			this.form.email = email
		},
		methods: {

			sendCode() {
				if (!this.$refs.uCode.canGetCode)
					return
				this.$refs['uForm'].setRules({
					email: this.rules.email
				})
				this.$refs['uForm'].validate((e) => {
					if (e) {
						uni.$once('verifyPopupEmailSuccess', this.verifySuccess)
						this.showSlideCode('verifyPopupEmailSuccess')
					}
				})
			},
			async verifySuccess(params) {
				this.getCode()
			},
			async getCode() {
				if (this.$refs['uCode'].canGetCode) {
					let data = {
						event: '',
						email: this.form.email,
						session: this.getSession(),
					}
					data.event = this.getCodeType('email')
					await this.$u.api.sendEmailCode(data)
					this.$u.toast('验证码已发送')
					this.$refs.uCode.start()
				}
			},
			save() {
				this.$refs['uForm'].setRules(this.rules)
				this.$refs['uForm'].validate(async (e) => {
					if (e) {
						this.ok({
							type: 'email',
							...this.form
						})
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.btns {
		width: 100%;
		margin-left: 130rpx;
		margin-top: 30rpx;

		.submit-btn {
			display: inline-block;
			width: 200rpx;
			height: 60rpx;
			line-height: 60rpx;
		}
	}
</style>